import './CalendarNavigationIcon.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../../helpers/classnames';
import { Icon } from '../../../Icon';
import type { CalendarNavigationIconProps } from './CalendarNavigationIcon.types';

export const CalendarNavigationIcon: FC<CalendarNavigationIconProps> = ({
	className: customClassName,
	direction,
	onClick,
	disabled = false,
	dataTestId,
}) => {
	const className = classNames('dsb_calendar_icon', customClassName, {
		disabled,
	});
	const onClickHandler = disabled ? undefined : onClick;

	return (
		<Icon iconName={direction} className={className} onClick={onClickHandler} size="large" dataTestId={dataTestId} />
	);
};
